valid:
  # Using AppProviders (correct)
  - |
    import { AppProviders } from '@/providers/AppProviders'
    function App() {
      return <AppProviders><Child /></AppProviders>
    }
  # Using renderWithMantine (correct)
  - |
    import { renderWithMantine } from '@/test/render'
    it('renders', () => {
      renderWithMantine(<MyComponent />)
    })
  # Inside AppProviders definition (allowed)
  - |
    export function AppProviders({ children }: Props) {
      return <MantineProvider theme={theme}>{children}</MantineProvider>
    }
invalid:
  # Bare MantineProvider in a component
  - |
    import { MantineProvider } from '@mantine/core'
    function App() {
      return <MantineProvider theme={theme}><Child /></MantineProvider>
    }
  # Bare MantineProvider in a test
  - |
    import { MantineProvider } from '@mantine/core'
    it('renders', () => {
      render(<MantineProvider><MyComponent /></MantineProvider>)
    })
"},"permission_updates":[]}}

